contract CounterV1{
    uint256 count;

    function initialize(uint256 _count) public {
        count = _count;
    }

    function increment() public {
        count += 1;
    }

    function getCount() public returns (uint256){
        return count;
    }

}

contract CounterV2 {
    uint256 count;


    function increment() public {
        count += 1;
    }

    function getCount() public returns (uint256){
        return count;
    }

    function decrement() public {
        count -= 1;
    }

    function reset() public {
        count = 0;
    }

    function incrementBy(uint256 amount) public{
        count += amount;
    }

}

